update draft_operation_lock
set operation_type = #{operationType},
    target_published_version = #{targetPublishedVersion},
    locked_by = #{lockedBy},
    locked_at = #{lockedAt},
    expires_at = #{expiresAt}
where draft_id = #{draftId}
  and expires_at <= #{now}

update draft_operation_lock
set locked_by = #{lockedBy},
    locked_at = #{lockedAt},
    expires_at = #{expiresAt}
where draft_id = #{draftId}
  and (
      (#{targetPublishedVersion} is null and target_published_version is null)
      or target_published_version = #{targetPublishedVersion}
  )

mapper.delete:
